from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    # Identify main subject (airport)
    main_subject = None
    for subject, triples_list in subject_map.items():
        if any(p in ["cityServed", "location", "runwayLength", "runwayName", "elevationAboveTheSeaLevel"] for p, _ in triples_list):
            main_subject = subject
            break

    if not main_subject and subject_map:
        main_subject = list(subject_map.keys())[0]

    if not main_subject:
        return "."

    # Create a single coherent sentence by organizing information logically
    sentence_parts = []

    # Handle location relationships first (most important for airports)
    location = None
    country = None
    is_part_of = None
    city_served = None

    for subject, triples_list in subject_map.items():
        for predicate, obj in triples_list:
            if predicate == "location":
                location = obj
            elif predicate == "country":
                country = obj
            elif predicate == "isPartOf":
                is_part_of = obj
            elif predicate == "cityServed":
                city_served = obj

    # Start with the main subject
    if city_served:
        sentence_parts.append(f"{main_subject} serves the city of {city_served}")
    elif location:
        sentence_parts.append(f"{main_subject} is located in {location}")
    else:
        sentence_parts.append(main_subject)

    # Add location hierarchy if available
    if is_part_of:
        sentence_parts.append(f", part of {is_part_of}")
    if country:
        sentence_parts.append(f", in {country}")

    # Handle other attributes with natural language patterns
    details = []

    for subject, triples_list in subject_map.items():
        for predicate, obj in triples_list:
            if predicate in ["location", "country", "isPartOf", "cityServed"]:
                continue  # Already handled

            if predicate == "mayor":
                details.append(f"The mayor of {subject} is {obj}")
            elif predicate == "leader":
                details.append(f"The leader of {subject} is {obj}")
            elif predicate == "language":
                details.append(f"{obj} is spoken in {subject}")
            elif predicate == "officialLanguage":
                details.append(f"{obj} is the official language of {subject}")
            elif predicate == "leaderParty":
                details.append(f"The leading party in {subject} is {obj}")
            elif predicate == "operatingOrganisation":
                details.append(f"It is operated by {obj}")
            elif predicate == "elevationAboveTheSeaLevel":
                details.append(f"It has an elevation of {obj} metres above sea level")
            elif predicate == "elevationAboveTheSeaLevelInFeet":
                details.append(f"It has an elevation of {obj} feet above sea level")
            elif predicate == "elevationAboveTheSeaLevelInMetres":
                details.append(f"It has an elevation of {obj} metres above sea level")
            elif predicate == "runwayLength":
                details.append(f"It has a runway length of {obj} metres")
            elif predicate == "runwayName":
                details.append(f"It has a runway named {obj}")
            elif predicate == "runwaySurfaceType":
                details.append(f"It has a runway surface type of {obj}")
            elif predicate == "1stRunwayLengthFeet":
                details.append(f"It has a first runway length of {obj} feet")
            elif predicate == "1stRunwaySurfaceType":
                details.append(f"It has a first runway surface type of {obj}")
            elif predicate == "3rdRunwayLengthFeet":
                details.append(f"It has a third runway length of {obj} feet")
            elif predicate == "icaoLocationIdentifier":
                details.append(f"It has an ICAO location identifier of {obj}")
            elif predicate == "locationIdentifier":
                details.append(f"It has a location identifier of {obj}")
            elif predicate == "iataLocationIdentifier":
                details.append(f"It has an IATA identifier of {obj}")
            elif predicate == "nativeName":
                details.append(f"It has a native name of {obj}")
            elif predicate == "owner":
                details.append(f"It is owned by {obj}")
            elif predicate == "capital":
                details.append(f"It has a capital of {obj}")
            elif predicate == "demonym":
                details.append(f"Residents are called {obj}")
            else:
                # Fallback for any unknown predicate with natural phrasing
                details.append(f"{subject} has a {predicate} of {obj}")

    # Combine all parts into a single coherent sentence
    if details:
        sentence_parts.append(". " + " ".join(details))
    else:
        sentence_parts.append(".")

    return "".join(sentence_parts)

